SELECT tipo_titulo, data_vencimento, data_referencia, taxa_anbima, intervalo_min_d0, intervalo_max_d0, intervalo_min_d1, intervalo_max_d1, pu, expressao, data_base, codigo_selic, codigo_isin, taxa_compra, taxa_venda, desvio_padrao, status FROM MERCADO_SECUNDARIO WHERE data_referencia BETWEEN ? AND ? ORDER BY data_referencia, tipo_titulo, data_vencimento
